import{_ as d,o as a,c as r,a2 as e}from"./chunks/framework.Bkqnpl2X.js";const u=JSON.parse('{"title":"附录C 常用材料许用应力速查","description":"","frontmatter":{},"headers":[],"relativePath":"guide/appendix/appendix-c.md","filePath":"guide/appendix/appendix-c.md","lastUpdated":1780443280000}'),h={name:"guide/appendix/appendix-c.md"};function o(n,t,l,i,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="附录c-常用材料许用应力速查" tabindex="-1">附录C 常用材料许用应力速查 <a class="header-anchor" href="#附录c-常用材料许用应力速查" aria-label="Permalink to &quot;附录C 常用材料许用应力速查&quot;">​</a></h1><p><strong>版本</strong>： V5.0 | <strong>所属</strong>：Avis航空航天阀门研发设计手册 | <strong>新增于</strong>：V5.0 <strong>数据来源</strong>：MMPDS-15、NASA-STD-6016、ASTM/AMS标准、公开材料数据。</p><hr><h2 id="c-1-镍基合金" tabindex="-1">C.1 镍基合金 <a class="header-anchor" href="#c-1-镍基合金" aria-label="Permalink to &quot;C.1 镍基合金&quot;">​</a></h2><h3 id="inconel-718-uns-n07718-—-航天阀门主力合金" tabindex="-1">Inconel 718 (UNS N07718) — 航天阀门主力合金 <a class="header-anchor" href="#inconel-718-uns-n07718-—-航天阀门主力合金" aria-label="Permalink to &quot;Inconel 718 (UNS N07718) — 航天阀门主力合金&quot;">​</a></h3><p>固溶(980°C)+时效(720/620°C)状态，AMS 5662（棒材）/ AMS 5663。</p><table tabindex="0"><thead><tr><th>温度</th><th>F_tu (MPa)</th><th>F_ty (MPa)</th><th>E (GPa)</th><th>延伸率(%)</th><th>ν</th><th>ρ (g/cm³)</th><th>F_su 剪切 (MPa)</th><th>备注</th></tr></thead><tbody><tr><td>20°C (RT)</td><td>1275</td><td>1035</td><td>205</td><td>12</td><td>0.29</td><td>8.19</td><td>765</td><td>AMS 5662 A-Basis</td></tr><tr><td>200°C</td><td>1210</td><td>980</td><td>198</td><td>12</td><td>0.29</td><td>—</td><td>726</td><td>B-Basis</td></tr><tr><td>400°C</td><td>1140</td><td>910</td><td>188</td><td>12</td><td>0.31</td><td>—</td><td>684</td><td>B-Basis</td></tr><tr><td>540°C</td><td>1080</td><td>860</td><td>175</td><td>12</td><td>0.33</td><td>—</td><td>648</td><td>B-Basis</td></tr><tr><td>650°C</td><td>980</td><td>790</td><td>165</td><td>15</td><td>0.34</td><td>—</td><td>588</td><td>限制使用温度</td></tr><tr><td>LH₂ (20K)</td><td>~1600 估</td><td>~1250 估</td><td>~220 估</td><td>~8 估</td><td>—</td><td>—</td><td>—</td><td>低温增强（FCC韧脆不转变优势）</td></tr><tr><td>LOX (90K)</td><td>~1500 估</td><td>~1180 估</td><td>~215 估</td><td>~10 估</td><td>—</td><td>—</td><td>—</td><td>低温增强</td></tr></tbody></table><p><strong>疲劳</strong>（RT, R=-1光滑棒, 10⁷ cycles, S-N B-Basis）: 10³≈850 MPa, 10⁴≈650 MPa, 10⁵≈500 MPa, 10⁶≈400 MPa, 10⁷≈350 MPa。</p><p><strong>蠕变</strong> — 650°C/690MPa, 1%总蠕变~100h, 断裂~300h；540°C/860MPa, 0.1%/100h。</p><hr><h3 id="inconel-625-uns-n06625-—-耐氢-耐腐蚀阀门" tabindex="-1">Inconel 625 (UNS N06625) — 耐氢/耐腐蚀阀门 <a class="header-anchor" href="#inconel-625-uns-n06625-—-耐氢-耐腐蚀阀门" aria-label="Permalink to &quot;Inconel 625 (UNS N06625) — 耐氢/耐腐蚀阀门&quot;">​</a></h3><p>退火状态，AMS 5599（薄板）/ AMS 5666（棒材）。</p><table tabindex="0"><thead><tr><th>温度</th><th>F_tu (MPa)</th><th>F_ty (MPa)</th><th>E (GPa)</th><th>ρ (g/cm³)</th><th>特点</th></tr></thead><tbody><tr><td>RT</td><td>830</td><td>414</td><td>208</td><td>8.44</td><td>高Mo (9%)→优异耐点蚀→适合LH₂环境, 但强度低于718</td></tr><tr><td>200°C</td><td>790</td><td>390</td><td>200</td><td>—</td><td>—</td></tr><tr><td>400°C</td><td>740</td><td>360</td><td>190</td><td>—</td><td>—</td></tr><tr><td>650°C</td><td>620</td><td>310</td><td>170</td><td>—</td><td>—</td></tr><tr><td>20K</td><td>~1000 估</td><td>~500 估</td><td>~225 估</td><td>—</td><td>低温增强</td></tr></tbody></table><hr><h3 id="monel-k-500-uns-n05500-—-lox阀门专用" tabindex="-1">Monel K-500 (UNS N05500) — LOX阀门专用 <a class="header-anchor" href="#monel-k-500-uns-n05500-—-lox阀门专用" aria-label="Permalink to &quot;Monel K-500 (UNS N05500) — LOX阀门专用&quot;">​</a></h3><p>时效硬化Ni-Cu合金（~63Ni-30Cu），AMS 4676（棒材）。</p><table tabindex="0"><thead><tr><th>温度</th><th>F_tu (MPa)</th><th>F_ty (MPa)</th><th>E (GPa)</th><th>ρ (g/cm³)</th></tr></thead><tbody><tr><td>RT</td><td>965</td><td>690</td><td>179</td><td>8.47</td></tr><tr><td>200°C</td><td>900</td><td>650</td><td>175</td><td>—</td></tr><tr><td>400°C</td><td>780</td><td>580</td><td>168</td><td>—</td></tr><tr><td>LOX (90K)</td><td>~1100 估</td><td>~800 估</td><td>—</td><td>—</td></tr></tbody></table><p><strong>关键应用</strong>：NASA LOX阀门标准材料——高铜含量（~30%）提供卓越的氧兼容性（NASA-STD-6001氧冲击/自燃试验→K-500远优于不锈钢）。</p><hr><h2 id="c-2-钛合金" tabindex="-1">C.2 钛合金 <a class="header-anchor" href="#c-2-钛合金" aria-label="Permalink to &quot;C.2 钛合金&quot;">​</a></h2><h3 id="ti-6al-4v-eli-ams-4928-—-低温优质钛" tabindex="-1">Ti-6Al-4V ELI (AMS 4928) — 低温优质钛 <a class="header-anchor" href="#ti-6al-4v-eli-ams-4928-—-低温优质钛" aria-label="Permalink to &quot;Ti-6Al-4V ELI (AMS 4928) — 低温优质钛&quot;">​</a></h3><p>β退火+时效，Grade 5/23（ELI低间隙）。</p><table tabindex="0"><thead><tr><th>温度</th><th>F_tu (MPa)</th><th>F_ty (MPa)</th><th>E (GPa)</th><th>ρ (g/cm³)</th><th>备注</th></tr></thead><tbody><tr><td>RT</td><td>895</td><td>828</td><td>114</td><td>4.43</td><td>AMS 4928</td></tr><tr><td>200°C</td><td>760</td><td>690</td><td>—</td><td>—</td><td>—</td></tr><tr><td>300°C</td><td>650</td><td>585</td><td>—</td><td>—</td><td>钛合金上限</td></tr><tr><td>20K</td><td>~1350 估</td><td>~1200 估</td><td>—</td><td>—</td><td>低温α-Ti六方结构→强度大幅提升→但韧性降低</td></tr></tbody></table><p><strong>注意</strong>：钛合金在LOX/GOX环境中存在钛火风险（NASA-STD-6001, NASA TM-2000-210620→钛阀在富氧高压下不可接受→仅用于燃料侧或惰性介质）。</p><hr><h2 id="c-3-奥氏体不锈钢" tabindex="-1">C.3 奥氏体不锈钢 <a class="header-anchor" href="#c-3-奥氏体不锈钢" aria-label="Permalink to &quot;C.3 奥氏体不锈钢&quot;">​</a></h2><h3 id="_304l-uns-s30403-316l-uns-s31603-—-低温-通用阀门" tabindex="-1">304L (UNS S30403) / 316L (UNS S31603) — 低温/通用阀门 <a class="header-anchor" href="#_304l-uns-s30403-316l-uns-s31603-—-低温-通用阀门" aria-label="Permalink to &quot;304L (UNS S30403) / 316L (UNS S31603) — 低温/通用阀门&quot;">​</a></h3><p>退火状态。316L因2%Mo→耐点蚀优于304L→优选推进剂兼容性场景。</p><table tabindex="0"><thead><tr><th>温度</th><th>304L F_tu/F_ty (MPa)</th><th>316L F_tu/F_ty (MPa)</th><th>E (GPa)</th><th>ρ (g/cm³)</th></tr></thead><tbody><tr><td>RT</td><td>485 / 172</td><td>515 / 205</td><td>193</td><td>8.00</td></tr><tr><td>200°C</td><td>430 / 150</td><td>460 / 180</td><td>—</td><td>—</td></tr><tr><td>400°C</td><td>395 / 127</td><td>420 / 155</td><td>—</td><td>—</td></tr><tr><td>20K</td><td>~1400 / ~800 估</td><td>~1400 / ~800 估</td><td>~205 估</td><td>—</td></tr></tbody></table><hr><h2 id="c-4-非金属密封材料" tabindex="-1">C.4 非金属密封材料 <a class="header-anchor" href="#c-4-非金属密封材料" aria-label="Permalink to &quot;C.4 非金属密封材料&quot;">​</a></h2><h3 id="ptfe-特氟龙" tabindex="-1">PTFE（特氟龙） <a class="header-anchor" href="#ptfe-特氟龙" aria-label="Permalink to &quot;PTFE（特氟龙）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>温度范围</th><th>拉伸强度(MPa)</th><th>硬度(Shore D)</th><th>摩擦系数(vs 钢)</th><th>限制</th></tr></thead><tbody><tr><td>-200°C 至 260°C</td><td>20-35</td><td>50-65</td><td>0.05-0.1</td><td>≤260°C→分解产生HF（氢氟酸→腐蚀阀体）→&gt;200°C不推荐用于阀门密封</td></tr></tbody></table><h3 id="kalrez-全氟弹性体-ffkm-—-航天密封金标准" tabindex="-1">Kalrez (全氟弹性体 FFKM) — 航天密封金标准 <a class="header-anchor" href="#kalrez-全氟弹性体-ffkm-—-航天密封金标准" aria-label="Permalink to &quot;Kalrez (全氟弹性体 FFKM) — 航天密封金标准&quot;">​</a></h3><table tabindex="0"><thead><tr><th>温度范围</th><th>压缩永久变形 (70h @200°C)</th><th>化学兼容性</th><th>应用</th></tr></thead><tbody><tr><td>-40°C 至 327°C</td><td>≤25%</td><td>全能（几乎对所有推进剂/溶剂惰性）</td><td>RS-25、Vulcain阀门密封面→弹性密封的世界顶级</td></tr></tbody></table><h3 id="peek-聚醚醚酮" tabindex="-1">PEEK (聚醚醚酮) <a class="header-anchor" href="#peek-聚醚醚酮" aria-label="Permalink to &quot;PEEK (聚醚醚酮)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>温度范围</th><th>拉伸强度(MPa)</th><th>热变形温度HDT(°C)</th><th>优点</th></tr></thead><tbody><tr><td>-100°C 至 260°C</td><td>90-100</td><td>152 (1.8MPa)</td><td>耐辐射→核推进阀；低放气(TML&lt;0.1%)→真空阀</td></tr></tbody></table><hr><h2 id="c-5-安全系数与许用应力选择指南" tabindex="-1">C.5 安全系数与许用应力选择指南 <a class="header-anchor" href="#c-5-安全系数与许用应力选择指南" aria-label="Permalink to &quot;C.5 安全系数与许用应力选择指南&quot;">​</a></h2><p>阀门结构设计通常采用<strong>安全系数法</strong>（与基于风险的设计互补，见第10章）。NASA和ECSS对有人/无人飞行器的差异：</p><table tabindex="0"><thead><tr><th>飞行器类型</th><th>屈曲FS</th><th>极限FS (拉伸/剪切)</th><th>密封面接触应力FS</th><th>参照标准</th></tr></thead><tbody><tr><td>载人 (HSF)</td><td>1.4×极限载荷</td><td>1.4</td><td>1.5×额定密封应力</td><td>NASA-STD-5012A</td></tr><tr><td>无人一次性</td><td>1.25×极限载荷</td><td>1.25</td><td>1.25×额定密封应力</td><td>NASA-STD-5012A</td></tr><tr><td>可重复使用</td><td>1.4×（附加ISE系数1.1-1.5）</td><td>1.4</td><td>1.5×（考虑多次循环降额）</td><td>NASA-STD-5012A + 任务专用</td></tr></tbody></table><p><strong>有限寿命例外</strong>：当阀门零件被定义为&quot;有限寿命件（LLI, Life-Limited Item）&quot;——每次飞行后检查或每N次飞行后强制更换——安全系数可适当降低，需经过独立的Fracture Control Board批准。</p><hr><blockquote><p><strong>附录C编写说明——2026年6月V5.0新增</strong>：所有性能数据标注&quot;A-Basis&quot;（统计95%置信下限，99%总体）或&quot;B-Basis&quot;（95%置信下限，90%总体），与MMPDS统计格式一致。标注&quot;估&quot;的数据基于低温物理规律外推（FCC韧脆不变→低温强度提升~15-30%），非MMPDS数据库的正式A/B-Basis值。所有数据仅供初步选材参考——飞行硬件许用应力必须基于具体批次的炉号力学性能和试验大纲（见第35章）。 <em>（内容由AI生成，仅供参考）</em><em>（内容由AI生成，仅供参考）</em></p></blockquote>',44)])])}const S=d(h,[["render",o]]);export{u as __pageData,S as default};
